const input = $input.first().json;
const action = input.action || '';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

const allCreds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.hubspot&select=cred_key,cred_value',
  headers: pgHeaders
});
const creds = {};
for (const c of (allCreds || [])) creds[c.cred_key] = c.cred_value;
if (!creds.hubspot_pat) {
  return [{ json: { error: 'HubSpot PAT not configured. Create a Private App at Settings -> Integrations -> Private Apps and paste the Access Token (pat-eu1-... / pat-na1-...).' } }];
}

const API = 'https://api.hubapi.com';
const authHeaders = { 'Authorization': 'Bearer ' + creds.hubspot_pat };
const jsonHeaders = Object.assign({}, authHeaders, { 'Content-Type': 'application/json' });

function truncate(text, max) {
  max = max || 5000;
  if (text.length > max) return text.substring(0, max) + '\n\n... (truncated, ' + text.length + ' chars total)';
  return text;
}

function errMsg(err) {
  if (err.response && err.response.body) {
    const b = err.response.body;
    if (typeof b === 'string') return b;
    if (b.message) return b.message + (b.correlationId ? ' (corr: ' + b.correlationId + ')' : '');
    return JSON.stringify(b);
  }
  if (err.message) return err.message;
  return String(err);
}

async function hsGet(path) {
  return await helpers.httpRequest({ method: 'GET', url: API + path, headers: authHeaders, json: true });
}
async function hsPost(path, body) {
  return await helpers.httpRequest({ method: 'POST', url: API + path, headers: jsonHeaders, body: body, json: true });
}
async function hsPatch(path, body) {
  return await helpers.httpRequest({ method: 'PATCH', url: API + path, headers: jsonHeaders, body: body, json: true });
}
async function hsPut(path, body) {
  return await helpers.httpRequest({ method: 'PUT', url: API + path, headers: jsonHeaders, body: body || {}, json: true });
}
async function hsDelete(path) {
  return await helpers.httpRequest({ method: 'DELETE', url: API + path, headers: authHeaders, json: true });
}

function nameOf(p) {
  return ((p.firstname || '') + ' ' + (p.lastname || '')).trim() || '(no name)';
}

function ymd(s) { return s ? String(s).substring(0, 10) : ''; }

// Association type IDs (HubSpot default associations, category HUBSPOT_DEFINED)
const ASSOC = {
  'notes->contacts': 202, 'notes->companies': 190, 'notes->deals': 214, 'notes->tickets': 228,
  'tasks->contacts': 204, 'tasks->companies': 192, 'tasks->deals': 216, 'tasks->tickets': 230
};

function buildAssocs(objType, inp) {
  // For create_note / create_task: turn associated_*_id into v3 associations array
  const assocs = [];
  const map = {
    associated_contact_id: 'contacts',
    associated_company_id: 'companies',
    associated_deal_id: 'deals',
    associated_ticket_id: 'tickets'
  };
  for (const [key, toType] of Object.entries(map)) {
    if (inp[key]) {
      const typeId = ASSOC[objType + '->' + toType];
      if (typeId) assocs.push({
        to: { id: String(inp[key]) },
        types: [{ associationCategory: 'HUBSPOT_DEFINED', associationTypeId: typeId }]
      });
    }
  }
  return assocs;
}

// === CONTACTS ===
if (action === 'list_contacts') {
  const limit = Math.min(parseInt(input.limit) || 10, 100);
  const props = 'firstname,lastname,email,phone,company,jobtitle,lifecyclestage';
  try {
    const r = await hsGet('/crm/v3/objects/contacts?limit=' + limit + '&properties=' + encodeURIComponent(props));
    const items = r.results || [];
    if (items.length === 0) return [{ json: { result: 'No contacts.' } }];
    let out = 'Contacts (' + items.length + '):\n';
    for (const c of items) {
      const p = c.properties || {};
      out += '  ' + c.id + ' - ' + nameOf(p) + (p.email ? ' <' + p.email + '>' : '') + (p.company ? ' @ ' + p.company : '') + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'HubSpot list_contacts: ' + errMsg(err) } }]; }

} else if (action === 'search_contacts') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required. Default search on "email". Override via "property" (e.g. firstname, lastname, phone, company) and "operator" (EQ, NEQ, CONTAINS_TOKEN, GT, LT, HAS_PROPERTY).' } }];
  const property = input.property || 'email';
  const operator = (input.operator || 'CONTAINS_TOKEN').toUpperCase();
  const limit = Math.min(parseInt(input.limit) || 10, 100);
  const body = {
    filterGroups: [{ filters: [{ propertyName: property, operator: operator, value: String(query) }] }],
    properties: ['firstname', 'lastname', 'email', 'phone', 'company', 'jobtitle'],
    limit: limit
  };
  try {
    const r = await hsPost('/crm/v3/objects/contacts/search', body);
    const items = r.results || [];
    if (items.length === 0) return [{ json: { result: 'No matches for ' + property + ' ' + operator + ' "' + query + '".' } }];
    let out = 'Matches (' + items.length + '):\n';
    for (const c of items) {
      const p = c.properties || {};
      out += '  ' + c.id + ' - ' + nameOf(p) + (p.email ? ' <' + p.email + '>' : '') + (p.company ? ' @ ' + p.company : '') + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'HubSpot search_contacts: ' + errMsg(err) } }]; }

} else if (action === 'get_contact') {
  const id = input.contact_id || input.id;
  const email = input.email;
  if (!id && !email) return [{ json: { error: 'Parameter "contact_id" or "email" is required.' } }];
  const props = 'firstname,lastname,email,phone,company,jobtitle,lifecyclestage,hs_lead_status,createdate,lastmodifieddate';
  try {
    const path = id
      ? '/crm/v3/objects/contacts/' + encodeURIComponent(id) + '?properties=' + encodeURIComponent(props)
      : '/crm/v3/objects/contacts/' + encodeURIComponent(email) + '?idProperty=email&properties=' + encodeURIComponent(props);
    const c = await hsGet(path);
    const p = c.properties || {};
    let out = 'Contact ' + c.id + ' - ' + nameOf(p) + '\n';
    if (p.email) out += 'Email: ' + p.email + '\n';
    if (p.phone) out += 'Phone: ' + p.phone + '\n';
    if (p.company) out += 'Company: ' + p.company + '\n';
    if (p.jobtitle) out += 'Job: ' + p.jobtitle + '\n';
    if (p.lifecyclestage) out += 'Lifecycle: ' + p.lifecyclestage + '\n';
    if (p.hs_lead_status) out += 'Lead status: ' + p.hs_lead_status + '\n';
    if (p.createdate) out += 'Created: ' + ymd(p.createdate) + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'HubSpot get_contact: ' + errMsg(err) } }]; }

} else if (action === 'create_contact') {
  if (!input.email && !input.firstname && !input.lastname) return [{ json: { error: 'At least "email", "firstname" or "lastname" is required.' } }];
  const props = {};
  const fields = ['email', 'firstname', 'lastname', 'phone', 'company', 'jobtitle', 'lifecyclestage'];
  for (const f of fields) if (input[f] !== undefined && input[f] !== '') props[f] = input[f];
  try {
    const c = await hsPost('/crm/v3/objects/contacts', { properties: props });
    return [{ json: { result: 'Contact created: ' + c.id + (props.email ? ' <' + props.email + '>' : '') } }];
  } catch (err) { return [{ json: { error: 'HubSpot create_contact: ' + errMsg(err) } }]; }

} else if (action === 'update_contact') {
  const id = input.contact_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "contact_id" is required.' } }];
  const props = {};
  const fields = ['email', 'firstname', 'lastname', 'phone', 'company', 'jobtitle', 'lifecyclestage', 'hs_lead_status'];
  for (const f of fields) if (input[f] !== undefined && input[f] !== '') props[f] = input[f];
  if (Object.keys(props).length === 0) return [{ json: { error: 'Provide at least one updatable field: ' + fields.join(', ') } }];
  try {
    const c = await hsPatch('/crm/v3/objects/contacts/' + encodeURIComponent(id), { properties: props });
    return [{ json: { result: 'Contact ' + c.id + ' updated.' } }];
  } catch (err) { return [{ json: { error: 'HubSpot update_contact: ' + errMsg(err) } }]; }

} else if (action === 'delete_contact') {
  const id = input.contact_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "contact_id" is required.' } }];
  try {
    await hsDelete('/crm/v3/objects/contacts/' + encodeURIComponent(id));
    return [{ json: { result: 'Contact ' + id + ' archived. Can be restored within 90 days in HubSpot UI.' } }];
  } catch (err) { return [{ json: { error: 'HubSpot delete_contact: ' + errMsg(err) } }]; }

// === COMPANIES ===
} else if (action === 'search_companies') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required. Default search on "name". Override via "property" (e.g. domain, industry, country) and "operator".' } }];
  const property = input.property || 'name';
  const operator = (input.operator || 'CONTAINS_TOKEN').toUpperCase();
  const limit = Math.min(parseInt(input.limit) || 10, 100);
  const body = {
    filterGroups: [{ filters: [{ propertyName: property, operator: operator, value: String(query) }] }],
    properties: ['name', 'domain', 'phone', 'city', 'country', 'industry', 'numberofemployees'],
    limit: limit
  };
  try {
    const r = await hsPost('/crm/v3/objects/companies/search', body);
    const items = r.results || [];
    if (items.length === 0) return [{ json: { result: 'No matches for ' + property + ' ' + operator + ' "' + query + '".' } }];
    let out = 'Matches (' + items.length + '):\n';
    for (const c of items) {
      const p = c.properties || {};
      out += '  ' + c.id + ' - ' + (p.name || '(no name)') + (p.domain ? ' (' + p.domain + ')' : '') + (p.country ? ' ' + p.country : '') + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'HubSpot search_companies: ' + errMsg(err) } }]; }

} else if (action === 'get_company') {
  const id = input.company_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "company_id" is required.' } }];
  const props = 'name,domain,phone,address,city,state,country,zip,industry,description,numberofemployees,annualrevenue,website,createdate';
  try {
    const c = await hsGet('/crm/v3/objects/companies/' + encodeURIComponent(id) + '?properties=' + encodeURIComponent(props));
    const p = c.properties || {};
    let out = 'Company ' + c.id + ' - ' + (p.name || '(no name)') + '\n';
    if (p.domain) out += 'Domain: ' + p.domain + '\n';
    if (p.website) out += 'Website: ' + p.website + '\n';
    if (p.phone) out += 'Phone: ' + p.phone + '\n';
    const loc = [p.city, p.state, p.country].filter(Boolean).join(', ');
    if (loc) out += 'Location: ' + loc + '\n';
    if (p.industry) out += 'Industry: ' + p.industry + '\n';
    if (p.numberofemployees) out += 'Employees: ' + p.numberofemployees + '\n';
    if (p.annualrevenue) out += 'Revenue: ' + p.annualrevenue + '\n';
    if (p.description) out += 'Description: ' + p.description.substring(0, 300) + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'HubSpot get_company: ' + errMsg(err) } }]; }

} else if (action === 'create_company') {
  if (!input.name && !input.domain) return [{ json: { error: 'At least "name" or "domain" is required.' } }];
  const props = {};
  const fields = ['name', 'domain', 'phone', 'city', 'state', 'country', 'industry', 'description', 'numberofemployees', 'website'];
  for (const f of fields) if (input[f] !== undefined && input[f] !== '') props[f] = input[f];
  try {
    const c = await hsPost('/crm/v3/objects/companies', { properties: props });
    return [{ json: { result: 'Company created: ' + c.id + ' - ' + (props.name || props.domain) } }];
  } catch (err) { return [{ json: { error: 'HubSpot create_company: ' + errMsg(err) } }]; }

} else if (action === 'update_company') {
  const id = input.company_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "company_id" is required.' } }];
  const props = {};
  const fields = ['name', 'domain', 'phone', 'city', 'state', 'country', 'industry', 'description', 'numberofemployees', 'website'];
  for (const f of fields) if (input[f] !== undefined && input[f] !== '') props[f] = input[f];
  if (Object.keys(props).length === 0) return [{ json: { error: 'Provide at least one updatable field: ' + fields.join(', ') } }];
  try {
    const c = await hsPatch('/crm/v3/objects/companies/' + encodeURIComponent(id), { properties: props });
    return [{ json: { result: 'Company ' + c.id + ' updated.' } }];
  } catch (err) { return [{ json: { error: 'HubSpot update_company: ' + errMsg(err) } }]; }

} else if (action === 'delete_company') {
  const id = input.company_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "company_id" is required.' } }];
  try {
    await hsDelete('/crm/v3/objects/companies/' + encodeURIComponent(id));
    return [{ json: { result: 'Company ' + id + ' archived. Can be restored within 90 days in HubSpot UI.' } }];
  } catch (err) { return [{ json: { error: 'HubSpot delete_company: ' + errMsg(err) } }]; }

// === DEALS ===
} else if (action === 'list_deals') {
  const limit = Math.min(parseInt(input.limit) || 10, 100);
  const props = 'dealname,amount,dealstage,pipeline,closedate,hubspot_owner_id,createdate';
  try {
    const r = await hsGet('/crm/v3/objects/deals?limit=' + limit + '&properties=' + encodeURIComponent(props));
    const items = r.results || [];
    if (items.length === 0) return [{ json: { result: 'No deals.' } }];
    let out = 'Deals (' + items.length + '):\n';
    for (const d of items) {
      const p = d.properties || {};
      out += '  ' + d.id + ' - ' + (p.dealname || '(no name)') + (p.amount ? ' ' + p.amount : '') + (p.dealstage ? ' [' + p.dealstage + ']' : '') + (p.closedate ? ' close: ' + ymd(p.closedate) : '') + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'HubSpot list_deals: ' + errMsg(err) } }]; }

} else if (action === 'search_deals') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required. Default search on "dealname". Override via "property" (e.g. dealstage, amount, hubspot_owner_id) and "operator" (EQ, GT, LT, CONTAINS_TOKEN).' } }];
  const property = input.property || 'dealname';
  const operator = (input.operator || 'CONTAINS_TOKEN').toUpperCase();
  const limit = Math.min(parseInt(input.limit) || 10, 100);
  const body = {
    filterGroups: [{ filters: [{ propertyName: property, operator: operator, value: String(query) }] }],
    properties: ['dealname', 'amount', 'dealstage', 'pipeline', 'closedate', 'hubspot_owner_id'],
    limit: limit
  };
  try {
    const r = await hsPost('/crm/v3/objects/deals/search', body);
    const items = r.results || [];
    if (items.length === 0) return [{ json: { result: 'No matches for ' + property + ' ' + operator + ' "' + query + '".' } }];
    let out = 'Matches (' + items.length + '):\n';
    for (const d of items) {
      const p = d.properties || {};
      out += '  ' + d.id + ' - ' + (p.dealname || '(no name)') + (p.amount ? ' ' + p.amount : '') + (p.dealstage ? ' [' + p.dealstage + ']' : '') + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'HubSpot search_deals: ' + errMsg(err) } }]; }

} else if (action === 'get_deal') {
  const id = input.deal_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "deal_id" is required.' } }];
  const props = 'dealname,amount,dealstage,pipeline,closedate,hubspot_owner_id,dealtype,description,createdate,hs_lastmodifieddate';
  try {
    const d = await hsGet('/crm/v3/objects/deals/' + encodeURIComponent(id) + '?properties=' + encodeURIComponent(props) + '&associations=contacts,companies');
    const p = d.properties || {};
    let out = 'Deal ' + d.id + ' - ' + (p.dealname || '(no name)') + '\n';
    if (p.amount) out += 'Amount: ' + p.amount + '\n';
    if (p.dealstage) out += 'Stage: ' + p.dealstage + '\n';
    if (p.pipeline) out += 'Pipeline: ' + p.pipeline + '\n';
    if (p.closedate) out += 'Close date: ' + ymd(p.closedate) + '\n';
    if (p.hubspot_owner_id) out += 'Owner: ' + p.hubspot_owner_id + '\n';
    if (p.dealtype) out += 'Type: ' + p.dealtype + '\n';
    if (p.description) out += 'Description: ' + p.description.substring(0, 300) + '\n';
    if (d.associations) {
      if (d.associations.contacts && d.associations.contacts.results && d.associations.contacts.results.length) {
        out += 'Contacts: ' + d.associations.contacts.results.map(function(x){return x.id;}).join(', ') + '\n';
      }
      if (d.associations.companies && d.associations.companies.results && d.associations.companies.results.length) {
        out += 'Companies: ' + d.associations.companies.results.map(function(x){return x.id;}).join(', ') + '\n';
      }
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'HubSpot get_deal: ' + errMsg(err) } }]; }

} else if (action === 'create_deal') {
  if (!input.dealname) return [{ json: { error: 'Parameter "dealname" is required.' } }];
  const props = {};
  const fields = ['dealname', 'amount', 'dealstage', 'pipeline', 'closedate', 'hubspot_owner_id', 'dealtype', 'description'];
  for (const f of fields) if (input[f] !== undefined && input[f] !== '') props[f] = input[f];
  const associations = [];
  if (input.associated_contact_id) associations.push({ to: { id: String(input.associated_contact_id) }, types: [{ associationCategory: 'HUBSPOT_DEFINED', associationTypeId: 3 }] });
  if (input.associated_company_id) associations.push({ to: { id: String(input.associated_company_id) }, types: [{ associationCategory: 'HUBSPOT_DEFINED', associationTypeId: 5 }] });
  const body = { properties: props };
  if (associations.length) body.associations = associations;
  try {
    const d = await hsPost('/crm/v3/objects/deals', body);
    return [{ json: { result: 'Deal created: ' + d.id + ' - ' + props.dealname } }];
  } catch (err) { return [{ json: { error: 'HubSpot create_deal: ' + errMsg(err) } }]; }

} else if (action === 'update_deal') {
  const id = input.deal_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "deal_id" is required.' } }];
  const props = {};
  const fields = ['dealname', 'amount', 'dealstage', 'pipeline', 'closedate', 'hubspot_owner_id', 'dealtype', 'description'];
  for (const f of fields) if (input[f] !== undefined && input[f] !== '') props[f] = input[f];
  if (Object.keys(props).length === 0) return [{ json: { error: 'Provide at least one updatable field: ' + fields.join(', ') } }];
  try {
    const d = await hsPatch('/crm/v3/objects/deals/' + encodeURIComponent(id), { properties: props });
    return [{ json: { result: 'Deal ' + d.id + ' updated.' } }];
  } catch (err) { return [{ json: { error: 'HubSpot update_deal: ' + errMsg(err) } }]; }

} else if (action === 'delete_deal') {
  const id = input.deal_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "deal_id" is required.' } }];
  try {
    await hsDelete('/crm/v3/objects/deals/' + encodeURIComponent(id));
    return [{ json: { result: 'Deal ' + id + ' archived. Can be restored within 90 days in HubSpot UI.' } }];
  } catch (err) { return [{ json: { error: 'HubSpot delete_deal: ' + errMsg(err) } }]; }

// === TICKETS ===
} else if (action === 'search_tickets') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required. Default search on "subject". Override via "property" (e.g. hs_pipeline_stage, hs_ticket_priority, hubspot_owner_id) and "operator".' } }];
  const property = input.property || 'subject';
  const operator = (input.operator || 'CONTAINS_TOKEN').toUpperCase();
  const limit = Math.min(parseInt(input.limit) || 10, 100);
  const body = {
    filterGroups: [{ filters: [{ propertyName: property, operator: operator, value: String(query) }] }],
    properties: ['subject', 'content', 'hs_pipeline', 'hs_pipeline_stage', 'hs_ticket_priority', 'hubspot_owner_id', 'createdate'],
    limit: limit
  };
  try {
    const r = await hsPost('/crm/v3/objects/tickets/search', body);
    const items = r.results || [];
    if (items.length === 0) return [{ json: { result: 'No matches for ' + property + ' ' + operator + ' "' + query + '".' } }];
    let out = 'Matches (' + items.length + '):\n';
    for (const t of items) {
      const p = t.properties || {};
      out += '  ' + t.id + ' - ' + (p.subject || '(no subject)') + (p.hs_pipeline_stage ? ' [' + p.hs_pipeline_stage + ']' : '') + (p.hs_ticket_priority ? ' ' + p.hs_ticket_priority : '') + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'HubSpot search_tickets: ' + errMsg(err) } }]; }

} else if (action === 'get_ticket') {
  const id = input.ticket_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "ticket_id" is required.' } }];
  const props = 'subject,content,hs_pipeline,hs_pipeline_stage,hs_ticket_priority,hubspot_owner_id,source_type,createdate,hs_lastmodifieddate';
  try {
    const t = await hsGet('/crm/v3/objects/tickets/' + encodeURIComponent(id) + '?properties=' + encodeURIComponent(props) + '&associations=contacts,companies');
    const p = t.properties || {};
    let out = 'Ticket ' + t.id + ' - ' + (p.subject || '(no subject)') + '\n';
    if (p.hs_pipeline_stage) out += 'Stage: ' + p.hs_pipeline_stage + '\n';
    if (p.hs_pipeline) out += 'Pipeline: ' + p.hs_pipeline + '\n';
    if (p.hs_ticket_priority) out += 'Priority: ' + p.hs_ticket_priority + '\n';
    if (p.hubspot_owner_id) out += 'Owner: ' + p.hubspot_owner_id + '\n';
    if (p.source_type) out += 'Source: ' + p.source_type + '\n';
    if (p.content) out += 'Content: ' + p.content.substring(0, 500) + '\n';
    if (p.createdate) out += 'Created: ' + ymd(p.createdate) + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'HubSpot get_ticket: ' + errMsg(err) } }]; }

} else if (action === 'create_ticket') {
  if (!input.subject) return [{ json: { error: 'Parameter "subject" is required.' } }];
  const props = { subject: input.subject };
  const fields = ['content', 'hs_pipeline', 'hs_pipeline_stage', 'hs_ticket_priority', 'hubspot_owner_id', 'source_type'];
  for (const f of fields) if (input[f] !== undefined && input[f] !== '') props[f] = input[f];
  if (!props.hs_pipeline_stage) props.hs_pipeline_stage = '1';
  const associations = [];
  if (input.associated_contact_id) associations.push({ to: { id: String(input.associated_contact_id) }, types: [{ associationCategory: 'HUBSPOT_DEFINED', associationTypeId: 16 }] });
  if (input.associated_company_id) associations.push({ to: { id: String(input.associated_company_id) }, types: [{ associationCategory: 'HUBSPOT_DEFINED', associationTypeId: 26 }] });
  const body = { properties: props };
  if (associations.length) body.associations = associations;
  try {
    const t = await hsPost('/crm/v3/objects/tickets', body);
    return [{ json: { result: 'Ticket created: ' + t.id + ' - ' + props.subject } }];
  } catch (err) { return [{ json: { error: 'HubSpot create_ticket: ' + errMsg(err) } }]; }

} else if (action === 'update_ticket') {
  const id = input.ticket_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "ticket_id" is required.' } }];
  const props = {};
  const fields = ['subject', 'content', 'hs_pipeline', 'hs_pipeline_stage', 'hs_ticket_priority', 'hubspot_owner_id'];
  for (const f of fields) if (input[f] !== undefined && input[f] !== '') props[f] = input[f];
  if (Object.keys(props).length === 0) return [{ json: { error: 'Provide at least one updatable field: ' + fields.join(', ') } }];
  try {
    const t = await hsPatch('/crm/v3/objects/tickets/' + encodeURIComponent(id), { properties: props });
    return [{ json: { result: 'Ticket ' + t.id + ' updated.' } }];
  } catch (err) { return [{ json: { error: 'HubSpot update_ticket: ' + errMsg(err) } }]; }

} else if (action === 'delete_ticket') {
  const id = input.ticket_id || input.id;
  if (!id) return [{ json: { error: 'Parameter "ticket_id" is required.' } }];
  try {
    await hsDelete('/crm/v3/objects/tickets/' + encodeURIComponent(id));
    return [{ json: { result: 'Ticket ' + id + ' archived. Can be restored within 90 days in HubSpot UI.' } }];
  } catch (err) { return [{ json: { error: 'HubSpot delete_ticket: ' + errMsg(err) } }]; }

// === ENGAGEMENTS ===
} else if (action === 'create_note') {
  const body = input.body || input.note_body;
  if (!body) return [{ json: { error: 'Parameter "body" (note text) is required.' } }];
  const props = { hs_note_body: body, hs_timestamp: Date.now() };
  const assocs = buildAssocs('notes', input);
  const payload = { properties: props };
  if (assocs.length) payload.associations = assocs;
  try {
    const n = await hsPost('/crm/v3/objects/notes', payload);
    let out = 'Note created: ' + n.id;
    if (assocs.length) out += ' (associated with ' + assocs.length + ' object' + (assocs.length !== 1 ? 's' : '') + ')';
    return [{ json: { result: out } }];
  } catch (err) { return [{ json: { error: 'HubSpot create_note: ' + errMsg(err) } }]; }

} else if (action === 'create_task') {
  const subject = input.subject;
  if (!subject) return [{ json: { error: 'Parameter "subject" is required.' } }];
  const props = {
    hs_task_subject: subject,
    hs_timestamp: Date.now()
  };
  if (input.body) props.hs_task_body = input.body;
  if (input.priority) props.hs_task_priority = String(input.priority).toUpperCase();
  if (input.status) props.hs_task_status = String(input.status).toUpperCase();
  if (input.type) props.hs_task_type = String(input.type).toUpperCase();
  if (input.hubspot_owner_id) props.hubspot_owner_id = input.hubspot_owner_id;
  if (input.due_date) {
    const d = new Date(input.due_date);
    if (!isNaN(d.getTime())) props.hs_task_due_date = d.getTime();
  }
  const assocs = buildAssocs('tasks', input);
  const payload = { properties: props };
  if (assocs.length) payload.associations = assocs;
  try {
    const t = await hsPost('/crm/v3/objects/tasks', payload);
    let out = 'Task created: ' + t.id + ' - ' + subject;
    if (assocs.length) out += ' (associated with ' + assocs.length + ' object' + (assocs.length !== 1 ? 's' : '') + ')';
    return [{ json: { result: out } }];
  } catch (err) { return [{ json: { error: 'HubSpot create_task: ' + errMsg(err) } }]; }

// === ASSOCIATIONS (v4) ===
} else if (action === 'associate_objects') {
  const fromType = input.from_type;
  const fromId = input.from_id;
  const toType = input.to_type;
  const toId = input.to_id;
  if (!fromType || !fromId || !toType || !toId) return [{ json: { error: 'Parameters "from_type", "from_id", "to_type", "to_id" are all required. Types: contacts, companies, deals, tickets, notes, tasks.' } }];
  try {
    await hsPut('/crm/v4/objects/' + encodeURIComponent(fromType) + '/' + encodeURIComponent(fromId) + '/associations/default/' + encodeURIComponent(toType) + '/' + encodeURIComponent(toId));
    return [{ json: { result: 'Associated ' + fromType + ':' + fromId + ' -> ' + toType + ':' + toId + ' (default association).' } }];
  } catch (err) { return [{ json: { error: 'HubSpot associate_objects: ' + errMsg(err) } }]; }

} else if (action === 'list_associations') {
  const fromType = input.from_type;
  const fromId = input.from_id;
  const toType = input.to_type;
  if (!fromType || !fromId || !toType) return [{ json: { error: 'Parameters "from_type", "from_id", "to_type" are required.' } }];
  const limit = Math.min(parseInt(input.limit) || 20, 100);
  try {
    const r = await hsGet('/crm/v4/objects/' + encodeURIComponent(fromType) + '/' + encodeURIComponent(fromId) + '/associations/' + encodeURIComponent(toType) + '?limit=' + limit);
    const items = r.results || [];
    if (items.length === 0) return [{ json: { result: 'No ' + toType + ' associated with ' + fromType + ':' + fromId + '.' } }];
    let out = 'Associated ' + toType + ' (' + items.length + '):\n';
    for (const a of items) {
      out += '  ' + (a.toObjectId || a.id) + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'HubSpot list_associations: ' + errMsg(err) } }]; }

// === META ===
} else if (action === 'list_pipelines') {
  const objType = input.object_type || 'deals';
  if (objType !== 'deals' && objType !== 'tickets') return [{ json: { error: 'Parameter "object_type" must be "deals" or "tickets".' } }];
  try {
    const r = await hsGet('/crm/v3/pipelines/' + encodeURIComponent(objType));
    const pipelines = r.results || [];
    if (pipelines.length === 0) return [{ json: { result: 'No pipelines for ' + objType + '.' } }];
    let out = 'Pipelines for ' + objType + ' (' + pipelines.length + '):\n';
    for (const pl of pipelines) {
      out += '- ' + pl.id + ' "' + pl.label + '"\n';
      for (const s of (pl.stages || [])) {
        out += '    stage: ' + s.id + ' "' + s.label + '"' + (s.metadata && s.metadata.probability ? ' (p=' + s.metadata.probability + ')' : '') + '\n';
      }
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'HubSpot list_pipelines: ' + errMsg(err) } }]; }

} else if (action === 'list_owners') {
  const limit = Math.min(parseInt(input.limit) || 50, 100);
  try {
    const r = await hsGet('/crm/v3/owners?limit=' + limit);
    const items = r.results || [];
    if (items.length === 0) return [{ json: { result: 'No owners.' } }];
    let out = 'Owners (' + items.length + '):\n';
    for (const o of items) {
      const name = ((o.firstName || '') + ' ' + (o.lastName || '')).trim() || '(no name)';
      out += '  ' + o.id + ' - ' + name + (o.email ? ' <' + o.email + '>' : '') + (o.archived ? ' [archived]' : '') + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) { return [{ json: { error: 'HubSpot list_owners: ' + errMsg(err) } }]; }

} else {
  return [{ json: { error: 'Unknown action: "' + action + '". Available: list_contacts, search_contacts, get_contact, create_contact, update_contact, delete_contact, search_companies, get_company, create_company, update_company, delete_company, list_deals, search_deals, get_deal, create_deal, update_deal, delete_deal, search_tickets, get_ticket, create_ticket, update_ticket, delete_ticket, create_note, create_task, associate_objects, list_associations, list_pipelines, list_owners.' } }];
}
